pub fn format_size(bytes: u64) -> String {
    const UNITS: &[(&str, u64)] = &[
        ("B", 1),
        ("KB", 1024),
        ("MB", 1024 * 1024),
        ("GB", 1024 * 1024 * 1024),
    ];

    for &(unit, divisor) in UNITS.iter().rev() {
        if bytes >= divisor {
            return format!("{:.1} {}", bytes as f64 / divisor as f64, unit);
