//! CLI: commands and argument parsing via clap.

use std::io::IsTerminal;
use std::path::PathBuf;
use std::process;

use anyhow::{Context, Result};
use clap::{Args, Parser, Subcommand};
use dialoguer::MultiSelect;

use crate::config::{
    config_file, default_data_dir, ensure_config, get_data_dir, load_config, save_config,
    CLAUDE_DIR,
};
use crate::helpers::format_size;
use crate::ops::{
    collect_projects, do_backup, do_cleanup, do_commit, do_pull, do_push, do_restore, do_skills,
};
use crate::state::RunState;

// ── arg types ─────────────────────────────────────────────────────────────────

#[derive(Parser)]
#[command(name = "tidy-claude", version)]
#[command(about = "Backup, sync, and clean up Claude Code configuration")]
struct Cli {
    /// Enable verbose output
    #[arg(global = true, long)]
    debug: bool,

    #[command(subcommand)]
    command: Option<Commands>,
}

#[derive(Subcommand)]
enum Commands {
    /// Full sync: pull + restore + skills + backup + push
    Sync,

    /// Show git status of the backup repo
    Status,

    /// Show or update tidy-claude configuration
    Config(ConfigArgs),

    /// Remove old Claude session and conversation files
    Cleanup {
        /// Delete sessions older than N days (0 = all)
        #[arg(long, default_value = "7", value_name = "DAYS")]
        older_than: u32,

        /// Clean all projects without interactive selection
        #[arg(short = 'a', long = "all")]
        all_projects: bool,

        /// Show what would be deleted without deleting
        #[arg(long)]
        dry_run: bool,

        /// Include named sessions (excluded by default)
        #[arg(long)]
        with_named_sessions: bool,
    },
}

#[derive(Args)]
struct ConfigArgs {
    /// Set the data directory for backups
    #[arg(long, value_name = "PATH")]
    data_dir: Option<PathBuf>,

    /// Set the git remote URL for the backup repo
    #[arg(long, value_name = "URL")]
    remote_backup: Option<String>,
}

// ── entry point ───────────────────────────────────────────────────────────────

pub fn run() -> Result<()> {
    let cli = Cli::parse();
    let state = RunState::new(cli.debug);
    ensure_config()?;

    match cli.command.unwrap_or(Commands::Sync) {
        Commands::Sync => cmd_sync(&state),
        Commands::Status => cmd_status(),
        Commands::Config(args) => cmd_config(args),
        Commands::Cleanup {
            older_than,
            all_projects,
            dry_run,
            with_named_sessions,
        } => cmd_cleanup(&state, older_than, all_projects, dry_run, with_named_sessions),
    }
}

// ── sync ──────────────────────────────────────────────────────────────────────

fn cmd_sync(state: &RunState) -> Result<()> {
    let cfg = load_config()?;
    let remote = cfg
        .get("remote_backup")
        .and_then(|v| v.as_str())
        .unwrap_or("");
    if remote.is_empty() {
        println!("No remote configured. Run: tidy-claude config --remote-backup <git-url>");
        process::exit(1);
    }

    let backup_dir = get_data_dir()?;
    if !do_pull(state, &backup_dir)? {
        process::exit(1);
    }
    do_restore(state, &backup_dir)?;
    do_skills(state, &backup_dir)?;
    do_backup(state, &backup_dir)?;
    do_commit(state, &backup_dir, None)?;
    do_push(state, &backup_dir)?;
    println!("sync: up to date");
    Ok(())
}

// ── status ────────────────────────────────────────────────────────────────────

fn cmd_status() -> Result<()> {
    let backup_dir = get_data_dir()?;
    std::process::Command::new("git")
        .args(["status", "--short"])
        .current_dir(&backup_dir)
        .status()?;
    Ok(())
}

// ── config ────────────────────────────────────────────────────────────────────

fn cmd_config(args: ConfigArgs) -> Result<()> {
    if args.data_dir.is_none() && args.remote_backup.is_none() {
        let path = config_file();
        println!("config: {}", path.display());
        println!("{}", serde_json::to_string_pretty(&load_config()?)?);
        return Ok(());
    }

    let mut cfg = load_config()?;

    if let Some(dir) = args.data_dir {
        let s = dir.to_string_lossy().to_string();
        cfg["data_dir"] = serde_json::json!(s);
        println!("data_dir set to {s}");
    }

    if let Some(remote) = args.remote_backup {
        let data_dir = cfg
            .get("data_dir")
            .and_then(|v| v.as_str())
            .map(PathBuf::from)
            .unwrap_or_else(default_data_dir);
        let backup_dir = data_dir.join("backup");

        if !backup_dir.join(".git").exists() {
            std::fs::create_dir_all(&data_dir)?;
            let out = std::process::Command::new("git")
                .args(["clone", &remote, "backup"])
                .current_dir(&data_dir)
                .output()
                .context("git clone failed")?;
            if !out.status.success() {
                anyhow::bail!(
                    "git clone failed: {}",
                    String::from_utf8_lossy(&out.stderr)
                );
            }
        } else {
            let out = std::process::Command::new("git")
                .args(["remote", "set-url", "origin", &remote])
                .current_dir(&backup_dir)
                .output()
                .context("git remote set-url failed")?;
            if !out.status.success() {
                anyhow::bail!(
                    "git remote set-url failed: {}",
                    String::from_utf8_lossy(&out.stderr)
                );
            }
        }
        cfg["remote_backup"] = serde_json::json!(remote.clone());
        println!("remote_backup set to {remote}");
    }

    save_config(&cfg)?;
    Ok(())
}

// ── cleanup ───────────────────────────────────────────────────────────────────

fn cmd_cleanup(
    state: &RunState,
    older_than: u32,
    all_projects: bool,
    dry_run: bool,
    with_named_sessions: bool,
) -> Result<()> {
    let projects = collect_projects(&CLAUDE_DIR.join("projects"));

    if projects.is_empty() {
        println!("cleanup: no projects found");
        return Ok(());
    }

    let selected_paths: Vec<PathBuf> = if all_projects {
        projects.iter().map(|p| p.path.clone()).collect()
    } else {
        if !std::io::stdin().is_terminal() {
            anyhow::bail!("interactive mode requires a TTY; use --all");
        }
        let max_name = projects.iter().map(|p| p.display_name.len()).max().unwrap_or(0);
        let items: Vec<String> = projects
            .iter()
            .map(|p| {
                format!(
                    "{:<max_name$}  {:>10}   {} sessions",
                    p.display_name,
                    format_size(p.total_size),
                    p.session_count,
                )
            })
            .collect();

        let chosen = MultiSelect::new()
            .with_prompt("Select projects to clean (space = toggle, enter = confirm)")
            .items(&items)
            .interact_opt()?;

        match chosen {
            None => {
                println!("cleanup: cancelled");
                return Ok(());
            }
            Some(indices) => indices.into_iter().map(|i| projects[i].path.clone()).collect(),
        }
    };

    let path_refs: Vec<&std::path::Path> = selected_paths.iter().map(|p| p.as_path()).collect();
    let res = do_cleanup(state, &path_refs, older_than, dry_run, &CLAUDE_DIR, with_named_sessions)?;

    let prefix = if dry_run { "would free" } else { "freed" };
    let verb = if dry_run { "would delete" } else { "deleted" };
    let mut parts = Vec::new();
    if res.deleted_files > 0 {
        parts.push(format!("{} files", res.deleted_files));
    }
    if res.deleted_dirs > 0 {
        parts.push(format!("{} subagent dirs", res.deleted_dirs));
    }

    if parts.is_empty() {
        let age = if older_than > 0 {
            format!(" older than {older_than} days")
        } else {
            String::new()
        };
        println!("cleanup: nothing to delete{age}");
    } else {
        println!(
            "cleanup: {} {} | {} {}",
            verb,
            parts.join(", "),
            prefix,
            format_size(res.freed_bytes)
        );
    }
    Ok(())
}

//! Integration tests for the CLI — port of tests/test_config_cli.py.
//!
//! Each test runs the real binary via `assert_cmd` in a subprocess, with
//! `TIDY_CLAUDE_CONFIG_DIR` pointing to a fresh temp directory so the real
//! user configuration is never touched.

use std::fs;
use std::path::Path;
use std::process::Command;

use assert_cmd::prelude::*;
use predicates::prelude::*;
use tempfile::TempDir;

// ── helpers ───────────────────────────────────────────────────────────────────

/// Write a `config.json` in `dir` and return the `TempDir` handle.
fn setup_config(dir: &Path, config: &serde_json::Value) {
    fs::create_dir_all(dir).unwrap();
    fs::write(
        dir.join("config.json"),
        serde_json::to_string_pretty(config).unwrap() + "\n",
    )
    .unwrap();
}

/// Create a bare git repository and return its path as a string.
fn make_bare_remote(parent: &Path) -> String {
    let remote = parent.join("remote.git");
    fs::create_dir_all(&remote).unwrap();
    Command::new("git")
        .args(["init", "--bare"])
        .current_dir(&remote)
        .output()
        .expect("git init --bare failed");
    remote.to_string_lossy().into_owned()
}

/// Return a `Command` for the `tidy-claude` binary with the config dir preset.
fn tidy(config_dir: &Path) -> assert_cmd::Command {
    let mut cmd = assert_cmd::Command::cargo_bin("tidy-claude").unwrap();
    cmd.env("TIDY_CLAUDE_CONFIG_DIR", config_dir);
    cmd
}

// ── config show ───────────────────────────────────────────────────────────────

#[test]
fn config_shows_current_config() {
    let tmp = TempDir::new().unwrap();
    let config_dir = tmp.path().join("cfg");
    setup_config(&config_dir, &serde_json::json!({"data_dir": "/tmp/backups"}));

    tidy(&config_dir)
        .arg("config")
        .assert()
        .success()
        .stdout(predicate::str::contains(
            config_dir.join("config.json").to_string_lossy().as_ref(),
        ))
        .stdout(predicate::str::contains("/tmp/backups"));
}

#[test]
fn config_shows_defaults_when_no_file() {
    let tmp = TempDir::new().unwrap();
    let config_dir = tmp.path().join("cfg");
    // No config.json written — let ensure_config create defaults.

    tidy(&config_dir)
        .arg("config")
        .assert()
        .success()
        .stdout(predicate::str::contains("data_dir"));
}

// ── config --remote-backup ────────────────────────────────────────────────────

#[test]
fn config_set_remote_backup() {
    let tmp = TempDir::new().unwrap();
    let config_dir = tmp.path().join("cfg");
    let data_dir = tmp.path().join("data");
    let remote_url = make_bare_remote(tmp.path());

    setup_config(
        &config_dir,
        &serde_json::json!({"data_dir": data_dir.to_string_lossy().as_ref()}),
    );

    tidy(&config_dir)
        .args(["config", "--remote-backup", &remote_url])
        .assert()
        .success()
        .stdout(predicate::str::contains(format!(
            "remote_backup set to {remote_url}"
        )));

    // Config file on disk must contain the new remote
    let saved: serde_json::Value = serde_json::from_str(
        &fs::read_to_string(config_dir.join("config.json")).unwrap(),
    )
    .unwrap();
    assert_eq!(saved["remote_backup"].as_str().unwrap(), remote_url);
    assert_eq!(
        saved["data_dir"].as_str().unwrap(),
        data_dir.to_string_lossy().as_ref()
    );
}

#[test]
fn config_creates_backup_dir_and_git_repo() {
    let tmp = TempDir::new().unwrap();
    let config_dir = tmp.path().join("cfg");
    let data_dir = tmp.path().join("data");
    let remote_url = make_bare_remote(tmp.path());

    setup_config(
        &config_dir,
        &serde_json::json!({"data_dir": data_dir.to_string_lossy().as_ref()}),
    );

    tidy(&config_dir)
        .args(["config", "--remote-backup", &remote_url])
        .assert()
        .success();

    let backup_dir = data_dir.join("backup");
    assert!(backup_dir.is_dir(), "backup dir should be created");
    assert!(backup_dir.join(".git").is_dir(), ".git should exist");
}

#[test]
fn config_set_data_dir_and_remote_together() {
    let tmp = TempDir::new().unwrap();
    let config_dir = tmp.path().join("cfg");
    let remote_url = make_bare_remote(tmp.path());
    let new_data_dir = tmp.path().join("new-data");

    setup_config(&config_dir, &serde_json::json!({"data_dir": "/old"}));

    tidy(&config_dir)
        .args([
            "config",
            "--data-dir",
            new_data_dir.to_string_lossy().as_ref(),
            "--remote-backup",
            &remote_url,
        ])
        .assert()
        .success()
        .stdout(predicate::str::contains("data_dir set to"))
        .stdout(predicate::str::contains("remote_backup set to"));

    let saved: serde_json::Value = serde_json::from_str(
        &fs::read_to_string(config_dir.join("config.json")).unwrap(),
    )
    .unwrap();
    assert_eq!(saved["remote_backup"].as_str().unwrap(), remote_url);
    assert!(new_data_dir.join("backup").join(".git").is_dir());
}

#[test]
fn config_overwrite_existing_remote() {
    let tmp = TempDir::new().unwrap();
    let config_dir = tmp.path().join("cfg");
    let old_remote = make_bare_remote(tmp.path());
    let data_dir = tmp.path().join("data");
    let backup_dir = data_dir.join("backup");

    setup_config(
        &config_dir,
        &serde_json::json!({
            "data_dir": data_dir.to_string_lossy().as_ref(),
            "remote_backup": old_remote,
        }),
    );

    // Simulate a previously initialised backup repo
    fs::create_dir_all(&backup_dir).unwrap();
    Command::new("git")
        .args(["init"])
        .current_dir(&backup_dir)
        .output()
        .unwrap();
    Command::new("git")
        .args(["remote", "add", "origin", &old_remote])
        .current_dir(&backup_dir)
        .output()
        .unwrap();

    // Create the new remote
    let new_remote_dir = tmp.path().join("other-remote.git");
    fs::create_dir_all(&new_remote_dir).unwrap();
    Command::new("git")
        .args(["init", "--bare"])
        .current_dir(&new_remote_dir)
        .output()
        .unwrap();
    let new_remote = new_remote_dir.to_string_lossy().into_owned();

    tidy(&config_dir)
        .args(["config", "--remote-backup", &new_remote])
        .assert()
        .success();

    let saved: serde_json::Value = serde_json::from_str(
        &fs::read_to_string(config_dir.join("config.json")).unwrap(),
    )
    .unwrap();
    assert_eq!(saved["remote_backup"].as_str().unwrap(), new_remote);
}

// ── sync remote guard ─────────────────────────────────────────────────────────

#[test]
fn sync_fails_without_remote() {
    let tmp = TempDir::new().unwrap();
    let config_dir = tmp.path().join("cfg");
    setup_config(&config_dir, &serde_json::json!({"data_dir": "/tmp/d"}));

    tidy(&config_dir)
        .arg("sync")
        .assert()
        .failure()
        .stdout(predicate::str::contains("No remote configured"))
        .stdout(predicate::str::contains("--remote-backup"));
}

#[test]
fn sync_fails_with_empty_remote() {
    let tmp = TempDir::new().unwrap();
    let config_dir = tmp.path().join("cfg");
    setup_config(
        &config_dir,
        &serde_json::json!({"data_dir": "/tmp/d", "remote_backup": ""}),
    );

    tidy(&config_dir)
        .arg("sync")
        .assert()
        .failure()
        .stdout(predicate::str::contains("No remote configured"));
}

#[test]
fn default_invocation_fails_without_remote() {
    let tmp = TempDir::new().unwrap();
    let config_dir = tmp.path().join("cfg");
    setup_config(&config_dir, &serde_json::json!({"data_dir": "/tmp/d"}));

    // No subcommand → defaults to sync
    tidy(&config_dir)
        .assert()
        .failure()
        .stdout(predicate::str::contains("No remote configured"));
}

